/**
 * Analytics route handlers — connect HTTP-style requests to the AggregationService.
 *
 * Each handler validates input, delegates to the aggregation service, and
 * returns a structured response. Framework-agnostic: handlers accept typed
 * request objects and return typed response objects.
 */

import type { OrderStatus } from '../models/order.js';
import type {
  AggregationService,
  OrderSummary,
  StatusBreakdown,
  UserOrderStats,
  TimeBucket,
} from '../services/aggregation.service.js';
import { Logger } from '../utils/logger.js';

const VALID_STATUSES: OrderStatus[] = [
  'pending',
  'confirmed',
  'shipped',
  'delivered',
  'cancelled',
];

/**
 * Standard API response envelope.
 */
export interface ApiResponse<T> {
  success: boolean;
  data?: T;
  error?: string;
}

/**
 * Query parameters for the daily aggregation endpoint.
 */
export interface DailyAggregationQuery {
  startDate?: string;
  endDate?: string;
}

/**
 * Query parameters for the top users endpoint.
 */
export interface TopUsersQuery {
  limit?: string | number;
}

/**
 * Query parameters for the user stats endpoint.
 */
export interface UserStatsQuery {
  userId?: string;
}

/**
 * Route parameters for the revenue-by-status endpoint.
 */
export interface RevenueByStatusParams {
  status?: string;
}

/**
 * Analytics route handler collection.
 *
 * Depends on:
 * - AggregationService (service layer) for analytics computations
 */
export class AnalyticsRoutes {
  private logger = new Logger('AnalyticsRoutes');

  constructor(private aggregationService: AggregationService) {}

  /**
   * GET /analytics/summary
   *
   * Returns overall order summary statistics.
   */
  getOrderSummary(): ApiResponse<OrderSummary> {
    this.logger.info('Handling GET /analytics/summary');
    try {
      const data = this.aggregationService.getOrderSummary();
      return { success: true, data };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown error';
      this.logger.error(`Failed to get order summary: ${message}`);
      return { success: false, error: message };
    }
  }

  /**
   * GET /analytics/status-breakdown
   *
   * Returns order counts and revenue broken down by status.
   */
  getStatusBreakdown(): ApiResponse<StatusBreakdown[]> {
    this.logger.info('Handling GET /analytics/status-breakdown');
    try {
      const data = this.aggregationService.getStatusBreakdown();
      return { success: true, data };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown error';
      this.logger.error(`Failed to get status breakdown: ${message}`);
      return { success: false, error: message };
    }
  }

  /**
   * GET /analytics/user-stats?userId=...
   *
   * Returns per-user order statistics. Optionally filter by userId.
   */
  getUserStats(query: UserStatsQuery): ApiResponse<UserOrderStats[]> {
    this.logger.info('Handling GET /analytics/user-stats');
    try {
      const userId = query.userId?.trim();
      if (userId !== undefined && userId === '') {
        return { success: false, error: 'userId must not be empty' };
      }
      const data = this.aggregationService.getUserOrderStats(userId || undefined);
      return { success: true, data };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown error';
      this.logger.error(`Failed to get user stats: ${message}`);
      return { success: false, error: message };
    }
  }

  /**
   * GET /analytics/revenue/:status
   *
   * Returns total revenue for orders with the given status.
   */
  getRevenueByStatus(params: RevenueByStatusParams): ApiResponse<{ status: OrderStatus; revenue: number }> {
    this.logger.info('Handling GET /analytics/revenue/:status');

    const status = params.status?.trim();
    if (!status) {
      return { success: false, error: 'status parameter is required' };
    }
    if (!VALID_STATUSES.includes(status as OrderStatus)) {
      return {
        success: false,
        error: `Invalid status: ${status}. Must be one of: ${VALID_STATUSES.join(', ')}`,
      };
    }

    try {
      const revenue = this.aggregationService.getRevenueByStatus(status as OrderStatus);
      return { success: true, data: { status: status as OrderStatus, revenue } };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown error';
      this.logger.error(`Failed to get revenue by status: ${message}`);
      return { success: false, error: message };
    }
  }

  /**
   * GET /analytics/daily?startDate=YYYY-MM-DD&endDate=YYYY-MM-DD
   *
   * Returns daily order aggregations for the given date range.
   */
  getDailyAggregation(query: DailyAggregationQuery): ApiResponse<TimeBucket[]> {
    this.logger.info('Handling GET /analytics/daily');

    if (!query.startDate || !query.endDate) {
      return { success: false, error: 'startDate and endDate query parameters are required' };
    }

    const startDate = new Date(query.startDate);
    const endDate = new Date(query.endDate);

    if (isNaN(startDate.getTime())) {
      return { success: false, error: `Invalid startDate: ${query.startDate}` };
    }
    if (isNaN(endDate.getTime())) {
      return { success: false, error: `Invalid endDate: ${query.endDate}` };
    }

    try {
      const data = this.aggregationService.getDailyAggregation(startDate, endDate);
      return { success: true, data };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown error';
      this.logger.error(`Failed to get daily aggregation: ${message}`);
      return { success: false, error: message };
    }
  }

  /**
   * GET /analytics/top-users?limit=N
   *
   * Returns the top N users by total spending. Defaults to 10.
   */
  getTopUsers(query: TopUsersQuery): ApiResponse<UserOrderStats[]> {
    this.logger.info('Handling GET /analytics/top-users');

    const DEFAULT_LIMIT = 10;
    let limit = DEFAULT_LIMIT;

    if (query.limit !== undefined) {
      limit = typeof query.limit === 'number' ? query.limit : parseInt(query.limit, 10);
      if (isNaN(limit)) {
        return { success: false, error: `Invalid limit: ${query.limit}` };
      }
      if (limit < 1) {
        return { success: false, error: 'limit must be at least 1' };
      }
    }

    try {
      const data = this.aggregationService.getTopUsers(limit);
      return { success: true, data };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown error';
      this.logger.error(`Failed to get top users: ${message}`);
      return { success: false, error: message };
    }
  }
}

