import { describe, it, expect, beforeEach } from 'vitest';
import { AnalyticsRoutes } from '../../src/routes/analytics.routes.js';
import { AggregationService } from '../../src/services/aggregation.service.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { resetDatabase } from '../../src/utils/database.js';
import type { Order } from '../../src/models/order.js';

function makeOrder(overrides: Partial<Order> = {}): Order {
  return {
    id: 'order-0001',
    userId: 'user-0001',
    items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 25 }],
    total: 50,
    status: 'pending',
    createdAt: new Date('2025-01-15'),
    updatedAt: new Date('2025-01-15'),
    ...overrides,
  };
}

describe('AnalyticsRoutes', () => {
  let routes: AnalyticsRoutes;
  let orderRepo: OrderRepository;

  beforeEach(() => {
    resetDatabase();
    orderRepo = new OrderRepository();
    const aggregationService = new AggregationService(orderRepo);
    routes = new AnalyticsRoutes(aggregationService);
  });

  describe('getOrderSummary', () => {
    it('should return summary for empty dataset', () => {
      const result = routes.getOrderSummary();
      expect(result.success).toBe(true);
      expect(result.data).toEqual({
        totalOrders: 0,
        totalRevenue: 0,
        averageOrderValue: 0,
        minOrderValue: 0,
        maxOrderValue: 0,
      });
    });

    it('should return summary with orders', () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 100 }));
      orderRepo.save(makeOrder({ id: 'o2', total: 200 }));
      const result = routes.getOrderSummary();
      expect(result.success).toBe(true);
      expect(result.data!.totalOrders).toBe(2);
      expect(result.data!.totalRevenue).toBe(300);
      expect(result.data!.averageOrderValue).toBe(150);
    });
  });

  describe('getStatusBreakdown', () => {
    it('should return breakdown by status', () => {
      orderRepo.save(makeOrder({ id: 'o1', status: 'pending', total: 100 }));
      orderRepo.save(makeOrder({ id: 'o2', status: 'shipped', total: 200 }));
      orderRepo.save(makeOrder({ id: 'o3', status: 'pending', total: 50 }));
      const result = routes.getStatusBreakdown();
      expect(result.success).toBe(true);
      expect(result.data).toHaveLength(2);
      const pending = result.data!.find((b) => b.status === 'pending');
      expect(pending).toEqual({ status: 'pending', count: 2, revenue: 150 });
    });
  });

  describe('getUserStats', () => {
    it('should return stats for all users', () => {
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 100 }));
      orderRepo.save(makeOrder({ id: 'o2', userId: 'u2', total: 200 }));
      const result = routes.getUserStats({});
      expect(result.success).toBe(true);
      expect(result.data).toHaveLength(2);
    });

    it('should filter by userId', () => {
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 100 }));
      orderRepo.save(makeOrder({ id: 'o2', userId: 'u2', total: 200 }));
      const result = routes.getUserStats({ userId: 'u1' });
      expect(result.success).toBe(true);
      expect(result.data).toHaveLength(1);
      expect(result.data![0].userId).toBe('u1');
    });

    it('should reject empty userId', () => {
      const result = routes.getUserStats({ userId: '  ' });
      expect(result.success).toBe(false);
      expect(result.error).toContain('must not be empty');
    });
  });

  describe('getRevenueByStatus', () => {
    it('should return revenue for valid status', () => {
      orderRepo.save(makeOrder({ id: 'o1', status: 'shipped', total: 300 }));
      const result = routes.getRevenueByStatus({ status: 'shipped' });
      expect(result.success).toBe(true);
      expect(result.data).toEqual({ status: 'shipped', revenue: 300 });
    });

    it('should reject missing status', () => {
      const result = routes.getRevenueByStatus({});
      expect(result.success).toBe(false);
      expect(result.error).toContain('required');
    });

    it('should reject invalid status', () => {
      const result = routes.getRevenueByStatus({ status: 'invalid' });
      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid status');
    });
  });

  describe('getDailyAggregation', () => {
    it('should return daily buckets', () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 100, createdAt: new Date('2025-01-15') }));
      const result = routes.getDailyAggregation({
        startDate: '2025-01-14',
        endDate: '2025-01-16',
      });
      expect(result.success).toBe(true);
      expect(result.data).toHaveLength(3);
      const jan15 = result.data!.find((b) => b.period === '2025-01-15');
      expect(jan15!.orderCount).toBe(1);
      expect(jan15!.revenue).toBe(100);
    });

    it('should require both dates', () => {
      const result = routes.getDailyAggregation({ startDate: '2025-01-14' });
      expect(result.success).toBe(false);
      expect(result.error).toContain('required');
    });

    it('should reject invalid dates', () => {
      const result = routes.getDailyAggregation({
        startDate: 'not-a-date',
        endDate: '2025-01-16',
      });
      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid startDate');
    });

    it('should return error when startDate > endDate', () => {
      const result = routes.getDailyAggregation({
        startDate: '2025-01-20',
        endDate: '2025-01-10',
      });
      expect(result.success).toBe(false);
      expect(result.error).toContain('before or equal');
    });
  });

  describe('getTopUsers', () => {
    it('should return top users with default limit', () => {
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 100 }));
      orderRepo.save(makeOrder({ id: 'o2', userId: 'u2', total: 200 }));
      const result = routes.getTopUsers({});
      expect(result.success).toBe(true);
      expect(result.data![0].userId).toBe('u2');
    });

    it('should respect custom limit', () => {
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 100 }));
      orderRepo.save(makeOrder({ id: 'o2', userId: 'u2', total: 200 }));
      orderRepo.save(makeOrder({ id: 'o3', userId: 'u3', total: 300 }));
      const result = routes.getTopUsers({ limit: '2' });
      expect(result.success).toBe(true);
      expect(result.data).toHaveLength(2);
    });

    it('should accept numeric limit', () => {
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 100 }));
      const result = routes.getTopUsers({ limit: 1 });
      expect(result.success).toBe(true);
      expect(result.data).toHaveLength(1);
    });

    it('should reject invalid limit', () => {
      const result = routes.getTopUsers({ limit: 'abc' });
      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid limit');
    });

    it('should reject limit < 1', () => {
      const result = routes.getTopUsers({ limit: '0' });
      expect(result.success).toBe(false);
      expect(result.error).toContain('at least 1');
    });
  });
});

